import sqlite3

def construct_query(conditions):
    # Start with the base query
    query = "SELECT * FROM users WHERE "
    
    # List to hold the conditions as strings
    condition_strings = []
    
    # Iterate over each condition in the input list
    for condition in conditions:
        field = condition['field']
        op = condition['op']
        value = condition['value']
        
        # Convert the value to a string and escape single quotes
        if isinstance(value, str):
            value = f"'{value.replace("'", "''")}'"
        
        # Append the formatted condition to the list
        condition_strings.append(f"{field} {op} {value}")
    
    # Join all conditions with 'AND'
    full_query = query + " AND ".join(condition_strings)
    return full_query

def search(conditions):
    # Connect to your SQLite database (replace 'your_database.db' with your actual DB file)
    conn = sqlite3.connect('your_database.db')
    cursor = conn.cursor()
    
    # Construct the SQL query
    sql_query = construct_query(conditions)
    
    # Execute the query
    cursor.execute(sql_query)
    
    # Fetch all results
    results = cursor.fetchall()
    
    # Close the connection
    conn.close()
    
    return results

